            ForEach(Array(track.waypoints.enumerated()), id: \.offset) { wpIndex, waypoint in
                WaypointDot(
                    position: waypoint,
                    index: wpIndex,
                    color: color,
                    isSelected: isSelected,
                    onTap: { onWaypointTap?(wpIndex) },
                    onRightClick: { onWaypointRightClick?(wpIndex) }
                )
            }
        }
    }
}

/// Single waypoint marker
struct WaypointDot: View {
    let position: Position
    let index: Int
    let color: Color
    let isSelected: Bool
    var onTap: (() -> Void)?
    var onRightClick: (() -> Void)?

    var body: some View {
        ZStack {
            // Outer ring
            Circle()
                .fill(color)
                .frame(width: isSelected ? 16 : 12, height: isSelected ? 16 : 12)

            // Inner dot
            Circle()
                .fill(Color.white)
                .frame(width: isSelected ? 8 : 6, height: isSelected ? 8 : 6)

            // Index label
            Text("\(index + 1)")
                .font(.system(size: 9, weight: .bold))
                .foregroundColor(.white)
                .offset(y: -18)
                .shadow(color: .black, radius: 2)
        }
        .position(x: position.x, y: position.y)
        .onTapGesture {
            onTap?()
        }
        .contextMenu {
            Button("Delete Waypoint") {
                onRightClick?()
            }
        }
    }
}

